public class TrafficOptimizer {
    public static class Edge {
        String target;
        int density;
        public Edge(String target, int density) {
            this.target = target;
            this.density = density;
        }
    }

    public static class Graph {
        Map<String, List<Edge>> adj = new HashMap<>();
        public void addIntersection(String intersection) {
            adj.put(intersection, new ArrayList<>());
        }
        public void addRoad(String from, String to, int density) {
            adj.get(from).add(new Edge(to, density));
        }
    }

    public static Map<String, String> trafficOptimizer(Graph graph, String source) {
        Map<String, Integer> dist = new HashMap<>();
        Map<String, String> prev = new HashMap<>();
        PriorityQueue<String> pq = new PriorityQueue<>(Comparator.comparingInt(n -> dist.get(n)));
        for (String node : graph.adj.keySet()) dist.put(node, Integer.MAX_VALUE);
        dist.put(source, 0);
        pq.add(source);
        while (!pq.isEmpty()) {
            String u = pq.poll();
            for (Edge e : graph.adj.get(u)) {
                int alt = dist.get(u) + e.density;
                if (alt < dist.getOrDefault(e.target, Integer.MAX_VALUE)) {
                    dist.put(e.target, alt);
                    prev.put(e.target, u);
                    pq.add(e.target);
                }
            }
        }
        return prev;
    }
