import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;
import java.util.TreeSet;

public class NetworkAnalyzer {
    public static List<Integer> analyzeNetworkConnectivity(List<List<Integer>> graph) {
        int n = graph.size();
        int[] disc = new int[n];
        int[] low = new int[n];
        int[] parent = new int[n];
        boolean[] visited = new boolean[n];
        Arrays.fill(parent, -1);
        TreeSet<Integer> result = new TreeSet<>();
        int[] time = new int[1];

        for (int i = 0; i < n; i++) {
            if (!visited[i]) {
                articulationHelper(i, disc, low, parent, visited, graph, result, time);
            }
        }

        return new ArrayList<>(result);
    }

    private static void articulationHelper(int u, int[] disc, int[] low, int[] parent, boolean[] visited,
                                           List<List<Integer>> graph, TreeSet<Integer> result, int[] time) {
        visited[u] = true;
        disc[u] = time[0];
        low[u] = time[0];
        time[0]++;
        int children = 0;

        for (int v : graph.get(u)) {
            if (!visited[v]) {
                children++;
                parent[v] = u;
                articulationHelper(v, disc, low, parent, visited, graph, result, time);
                low[u] = Math.min(low[u], low[v]);
                if (parent[u] != -1 && low[v] >= disc[u]) {
                    result.add(u);
                }
            } else if (v != parent[u]) {
                low[u] = Math.min(low[u], disc[v]);
            }
        }

        if (parent[u] == -1 && children > 1) {
            result.add(u);
        }
    }
}
