        }
        ActionType::Deallocate => {
            let mut gates = GATES.lock().unwrap();
            if gates.remove(&gate_id) {
                Ok(format!("Deallocated gate {}", gate_id))
            } else {
                Err(format!("Gate {} was not allocated", gate_id))
            }
        }
        ActionType::Status => {
            let gates = GATES.lock().unwrap();
            if gates.contains(&gate_id) {
                Ok(format!("Gate {} is allocated", gate_id))
            } else {
                Ok(format!("Gate {} is available", gate_id))
            }
        }
