import java.util.concurrent.CopyOnWriteArrayList;

public class LoginHistoryManager {
    private static final Map<String, List<String>> loginHistory = new ConcurrentHashMap<>();
    private static final ObjectMapper mapper = new ObjectMapper();

    public static String processLoginHistory(String jsonInput) throws Exception {
        JsonNode root = mapper.readTree(jsonInput);
        String operation = root.get("operation").asText();
        JsonNode data = root.get("data");

        switch (operation) {
            case "add":
                String userId = data.get("userId").asText();
                String timestamp = data.get("timestamp").asText();
                loginHistory.computeIfAbsent(userId, k -> new CopyOnWriteArrayList<>()).add(timestamp);
                return mapper.writeValueAsString(Collections.singletonMap("status", "success"));
            case "retrieve":
                userId = data.get("userId").asText();
                int limit = data.has("limit") ? data.get("limit").asInt() : Integer.MAX_VALUE;
                List<String> history = loginHistory.getOrDefault(userId, Collections.emptyList());
                List<String> recent = history.subList(0, Math.min(limit, history.size()));
                return mapper.writeValueAsString(Collections.singletonMap("history", recent));
            case "delete":
                userId = data.get("userId").asText();
                loginHistory.remove(userId);
                return mapper.writeValueAsString(Collections.singletonMap("status", "success"));
            default:
                throw new IllegalArgumentException("Invalid operation");
        }
    }
}
