#include <vector>
#include <string>
#include <queue>
#include <algorithm>

using namespace std;

struct PermissionNode {
    string name;
    int level;
    vector<PermissionNode*> children;
};

struct OperationNode {
    string type;
    string path;
    string name;
    int level;
    vector<OperationNode*> children;
};

class PermissionTree {
public:
    PermissionNode* root;
};

class OperationTree {
public:
    OperationNode* root;
};

vector<string> split(const string& s, char delimiter) {
    vector<string> tokens;
    string token;
    for (char c : s) {
        if (c != delimiter) token += c;
        else { tokens.push_back(token); token.clear(); }
    }
    if (!token.empty()) tokens.push_back(token);
    return tokens;
}

PermissionNode* findNode(PermissionNode* node, const vector<string>& path, int index) {
    if (index >= path.size()) return nullptr;
    for (PermissionNode* child : node->children) {
        if (child->name == path[index]) {
            if (index == path.size() - 1) return child;
            return findNode(child, path, index + 1);
        }
    }
    return nullptr;
}

PermissionNode* findParent(PermissionNode* parent, PermissionNode* target) {
    for (PermissionNode* child : parent->children) {
        if (child == target) return parent;
        PermissionNode* result = findParent(child, target);
        if (result) return result;
    }
    return nullptr;
}

void managePermissions(PermissionTree& perm, OperationTree& ops) {
    queue<OperationNode*> q;
    if (ops.root) q.push(ops.root);

    while (!q.empty()) {
        OperationNode* op = q.front();
        q.pop();

        vector<string> path = split(op->path, '/');
        PermissionNode* target = perm.root;
        if (!path.empty()) {
            target = findNode(perm.root, path, 0);
        }

        if (op->type == "ADD") {
            PermissionNode* newNode = new PermissionNode{op->name, op->level, {}};
            if (target) target->children.push_back(newNode);
        } else if (op->type == "UPDATE" && target) {
            target->level = op->level;
        } else if (op->type == "REMOVE" && target) {
            PermissionNode* parent = findParent(perm.root, target);
            if (parent) {
                parent->children.erase(remove(parent->children.begin(), parent->children.end(), target), parent->children.end());
                delete target;
            }
        }

        for (OperationNode* child : op->children) q.push(child);
    }
}
