use std::collections::HashMap;

pub struct Tree {
    root: Node,
}

struct Node {
    name: String,
    config: HashMap<String, String>,
    children: Vec<Node>,
}

pub enum ActionType {
    Add,
    Update,
    Remove,
    Get,
}

impl Node {
    fn find_mut(&mut self, name: &str) -> Option<&mut Node> {
        if self.name == name {
            return Some(self);
        }
        for child in &mut self.children {
            if let Some(found) = child.find_mut(name) {
                return Some(found);
            }
        }
        None
    }

    fn find_parent_mut(&mut self, target: &str) -> Option<&mut Node> {
        for child in &mut self.children {
            if child.name == target {
                return Some(self);
            }
            if let Some(parent) = child.find_parent_mut(target) {
                return Some(parent);
            }
        }
        None
    }
}

impl Tree {
    pub fn new() -> Self {
        Tree {
            root: Node {
                name: String::new(),
                config: HashMap::new(),
                children: Vec::new(),
            },
        }
    }
}

pub fn manage_network_config(
    tree: &mut Tree,
    action: ActionType,
    params: HashMap<String, String>,
) -> Option<HashMap<String, String>> {
    match action {
        ActionType::Add => {
            let parent = tree.root.find_mut(params.get("parent_name")?)?;
            parent.children.push(Node {
                name: params.get("name")?.clone(),
                config: params
                    .iter()
                    .filter(|(k, _)| k != &"parent_name" && k != &"name")
                    .map(|(k, v)| (k.clone(), v.clone()))
                    .collect(),
                children: Vec::new(),
            });
            None
        }
        ActionType::Update => {
            let node = tree.root.find_mut(params.get("name")?)?;
            node.config = params
                .iter()
                .filter(|(k, _)| k != &"name")
                .map(|(k, v)| (k.clone(), v.clone()))
                .collect();
            None
        }
        ActionType::Remove => {
            let parent = tree.root.find_parent_mut(params.get("name")?)?;
            parent.children.retain(|child| child.name != *params.get("name")?);
            None
        }
        ActionType::Get => {
            Some(tree.root.find_mut(params.get("name")?)?.config.clone())
        }
    }
}
