import org.json.JSONObject;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class FileSystemSimulator {
    private static class Folder {
        String name;
        Folder parent;
        List<Folder> children = new ArrayList<>();

        Folder(String name) {
            this.name = name;
        }

        String getPath() {
            if (parent == null) return "/" + name;
            return parent.getPath() + "/" + name;
        }
    }

    private static Map<String, Folder> folders = new HashMap<>();
    private static Folder root = new Folder("root");

    static {
        folders.put("root", root);
    }

    public static String fs_simulator(String jsonInput) {
        JSONObject json = new JSONObject(jsonInput);
        String action = json.getString("action");
        String name = json.optString("name", null);

        switch (action) {
            case "add":
                String parentName = json.optString("parentName", "root");
                Folder parent = folders.get(parentName);
                if (parent != null && !folders.containsKey(name)) {
                    Folder newFolder = new Folder(name);
                    newFolder.parent = parent;
                    parent.children.add(newFolder);
                    folders.put(name, newFolder);
                }
                break;
            case "move":
                String newParentName = json.optString("newParent", "root");
                Folder folderToMove = folders.get(name);
                Folder newParent = folders.get(newParentName);
                if (folderToMove != null && newParent != null) {
                    folderToMove.parent.children.remove(folderToMove);
                    folderToMove.parent = newParent;
                    newParent.children.add(folderToMove);
                }
                break;
            case "remove":
                Folder folderToRemove = folders.get(name);
                if (folderToRemove != null) {
                    removeFolderAndChildren(folderToRemove);
                    if (folderToRemove.parent != null) {
                        folderToRemove.parent.children.remove(folderToRemove);
                    }
                    folders.remove(name);
                }
                break;
            case "fetch":
                Folder folder = folders.get(name);
                return folder != null ? folder.getPath() : "";
            default:
                break;
        }
        return "";
    }

    private static void removeFolderAndChildren(Folder folder) {
        for (Folder child : new ArrayList<>(folder.children)) {
            removeFolderAndChildren(child);
            folders.remove(child.name);
        }
        folder.children.clear();
    }
}
