fn calculate_divisors(n: i32) -> Vec<i32> {
    if n <= 0 {
        return Vec::new();
    }
    let mut divisors = Vec::new();
    let sqrt_n = (n as f64).sqrt() as i32;
    for i in 1..=sqrt_n {
        if n % i == 0 {
            divisors.push(i);
            let counterpart = n / i;
            if counterpart != i {
                divisors.push(counterpart);
            }
        }
    }
    divisors.sort();
    divisors
}
