#include <vector>
#include <queue>
#include <algorithm>
#include <climits>

using namespace std;

vector<int> findShortestPath(const vector<vector<pair<int, int>>>& Graph, int start, int end) {
    const int INF = INT_MAX;
    int n = Graph.size();
    vector<int> dist(n, INF);
    vector<int> prev(n, -1);
    dist[start] = 0;

    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;
    pq.emplace(0, start);

    while (!pq.empty()) {
        auto current = pq.top();
        pq.pop();
        int currentDist = current.first;
        int u = current.second;

        if (u == end) break;
        if (currentDist > dist[u]) continue;

        for (const auto& edge : Graph[u]) {
            int v = edge.first;
            int weight = edge.second;

            if (dist[u] + weight < dist[v]) {
                dist[v] = dist[u] + weight;
                prev[v] = u;
                pq.emplace(dist[v], v);
            }
        }
    }

    if (dist[end] == INF) return {};

    vector<int> path;
    for (int at = end; at != -1; at = prev[at]) {
        path.push_back(at);
    }
    reverse(path.begin(), path.end());

    return path;
}
