public static int[][] transformMatrix(int[][] matrix, String operation) {
    int rows = matrix.length;
    if (rows == 0) return new int[0][0];
    int cols = matrix[0].length;
    int[][] result;
    switch (operation) {
        case "rotate_left":
            result = new int[cols][rows];
            for (int i = 0; i < cols; i++) {
                for (int j = 0; j < rows; j++) {
                    result[i][j] = matrix[j][cols - 1 - i];
                }
            }
            break;
        case "rotate_right":
            result = new int[cols][rows];
            for (int i = 0; i < cols; i++) {
                for (int j = 0; j < rows; j++) {
                    result[i][j] = matrix[rows - 1 - j][i];
                }
            }
            break;
        case "flip_vertical":
            result = new int[rows][cols];
            for (int i = 0; i < rows; i++) {
                for (int j = 0; j < cols; j++) {
                    result[i][j] = matrix[i][cols - 1 - j];
                }
            }
            break;
        case "flip_horizontal":
            result = new int[rows][cols];
            for (int i = 0; i < rows; i++) {
                for (int j = 0; j < cols; j++) {
                    result[i][j] = matrix[rows - 1 - i][j];
                }
            }
            break;
        default:
            throw new IllegalArgumentException("Invalid operation");
    }
    return result;
}
